/**
 * @summary Receive incoming Twilio SMS/WhatsApp message
 */
export const getTwilioWebhookUrl = () => {
  return `/api/webhook/twilio`;
};

export const twilioWebhook = async (
  twilioWebhookInput: TwilioWebhookInput,
  options?: RequestInit,
): Promise<string> => {
  const formUrlEncoded = new URLSearchParams();
  if (twilioWebhookInput.From !== undefined) {
    formUrlEncoded.append(`From`, twilioWebhookInput.From);
  }
  if (twilioWebhookInput.Body !== undefined) {
    formUrlEncoded.append(`Body`, twilioWebhookInput.Body);
  }
  if (twilioWebhookInput.MessageSid !== undefined) {
    formUrlEncoded.append(`MessageSid`, twilioWebhookInput.MessageSid);
  }
  if (twilioWebhookInput.To !== undefined) {
    formUrlEncoded.append(`To`, twilioWebhookInput.To);
  }

  return customFetch<string>(getTwilioWebhookUrl(), {
    ...options,
    method: "POST",
    headers: {
      "Content-Type": "application/x-www-form-urlencoded",
      ...options?.headers,
    },
    body: formUrlEncoded,
  });
};

export const getTwilioWebhookMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof twilioWebhook>>,
    TError,
    { data: BodyType<TwilioWebhookInput> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof twilioWebhook>>,
  TError,
  { data: BodyType<TwilioWebhookInput> },
  TContext
> => {
  const mutationKey = ["twilioWebhook"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof twilioWebhook>>,
    { data: BodyType<TwilioWebhookInput> }
  > = (props) => {
    const { data } = props ?? {};

    return twilioWebhook(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type TwilioWebhookMutationResult = NonNullable<
  Awaited<ReturnType<typeof twilioWebhook>>
>;
export type TwilioWebhookMutationBody = BodyType<TwilioWebhookInput>;
export type TwilioWebhookMutationError = ErrorType<unknown>;

/**
 * @summary Receive incoming Twilio SMS/WhatsApp message
 */
export const useTwilioWebhook = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof twilioWebhook>>,
    TError,
    { data: BodyType<TwilioWebhookInput> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof twilioWebhook>>,
  TError,
  { data: BodyType<TwilioWebhookInput> },
  TContext
> => {
  return useMutation(getTwilioWebhookMutationOptions(options));
};
